     1→"use client";
     2→
     3→import { useState } from "react";
     4→import { socket } from "@/lib/socket";
     5→import { fetchRecommendations, submitReaction, submitOnboarding } from "@/lib/api";
     6→import type { Outfit, OnboardingData, RecommendationResponse } from "@/lib/types";
     7→
     8→// MVP hardcoded IDs — replace with Google OAuth later
     9→const USER_ID = "00000000-0000-0000-0000-000000000001";
    10→const SESSION_ID = "00000000-0000-0000-0000-000000000001";
    11→
    12→type PhoneState = "welcome" | "onboarding" | "loading" | "outfits" | "done";
    13→
    14→export default function PhonePage() {
    15→  const [state, setState] = useState<PhoneState>("welcome");
    16→  const [outfits, setOutfits] = useState<Outfit[]>([]);
    17→  const [currentIdx, setCurrentIdx] = useState(0);
    18→  const [liked, setLiked] = useState(0);
    19→  const [errorMsg, setErrorMsg] = useState("");
    20→  const [greeting, setGreeting] = useState("");
    21→
    22→  async function startSession() {
    23→    setState("loading");
    24→    socket.connect();
    25→    socket.emit("session_started", {
    26→      session_id: SESSION_ID,
    27→      user_id: USER_ID,
    28→    });
    29→
    30→    // Also call REST endpoint directly
    31→    try {
    32→      const result = await fetchRecommendations(SESSION_ID);
    33→      handleResult(result);
    34→    } catch {
    35→      setErrorMsg("Could not reach backend.");
    36→      setState("welcome");
    37→    }
    38→  }
    39→
    40→  function handleResult(result: RecommendationResponse) {
    41→    if (result.status === "success" && result.data) {
    42→      setGreeting(result.data.greeting);
    43→      setOutfits(result.data.outfits);
    44→      setCurrentIdx(0);
    45→      setLiked(0);
    46→      setState("outfits");
    47→    } else if (result.status === "needs_onboarding") {
    48→      setState("onboarding");
    49→    } else {
    50→      setErrorMsg(result.message ?? "Something went wrong.");
    51→      setState("welcome");
    52→    }
    53→  }
    54→
    55→  async function handleOnboardingSubmit(data: OnboardingData) {
    56→    setState("loading");
    57→    await submitOnboarding(USER_ID, data);
    58→    try {
    59→      const result = await fetchRecommendations(SESSION_ID);
    60→      handleResult(result);
    61→    } catch {
    62→      setErrorMsg("Could not reach backend.");
    63→      setState("welcome");
    64→    }
    65→  }
    66→
    67→  async function handleReaction(reaction: "liked" | "disliked" | "skipped") {
    68→    if (reaction === "liked") setLiked((n) => n + 1);
    69→
    70→    // Fire-and-forget reaction update
    71→    const outfitId = outfits[currentIdx]?.id;
    72→    if (outfitId) {
    73→      submitReaction(outfitId, reaction).catch(() => {});
    74→    }
    75→
    76→    if (currentIdx + 1 < outfits.length) {
    77→      setCurrentIdx((i) => i + 1);
    78→    } else {
    79→      setState("done");
    80→    }
    81→  }
    82→
    83→  return (
    84→    <main
    85→      style={{
    86→        minHeight: "100vh",
    87→        fontFamily: "'Helvetica Neue', Arial, sans-serif",
    88→        background: "#fafafa",
    89→        color: "#111",
    90→      }}
    91→    >
    92→      {state === "welcome" && (
    93→        <WelcomeView onStart={startSession} error={errorMsg} />
    94→      )}
    95→      {state === "onboarding" && (
    96→        <OnboardingView onSubmit={handleOnboardingSubmit} />
    97→      )}
    98→      {state === "loading" && <PhoneLoadingView />}
    99→      {state === "outfits" && outfits[currentIdx] && (
   100→        <OutfitCardView
   101→          outfit={outfits[currentIdx]}
   102→          index={currentIdx}
   103→          total={outfits.length}
   104→          greeting={greeting}
   105→          onReaction={handleReaction}
   106→        />
   107→      )}
   108→      {state === "done" && (
   109→        <DoneView liked={liked} total={outfits.length} onRestart={() => setState("welcome")} />
   110→      )}
   111→    </main>
   112→  );
   113→}
   114→
   115→/* ---------- Sub-views ---------- */
   116→
   117→function WelcomeView({ onStart, error }: { onStart: () => void; error: string }) {
   118→  return (
   119→    <div
   120→      style={{
   121→        display: "flex",
   122→        flexDirection: "column",
   123→        alignItems: "center",
   124→        justifyContent: "center",
   125→        height: "100vh",
   126→        padding: 32,
   127→        textAlign: "center",
   128→      }}
   129→    >
   130→      <h1 style={{ fontSize: 32, fontWeight: 700, marginBottom: 8 }}>
   131→        Mirrorless
   132→      </h1>
   133→      <p style={{ fontSize: 16, color: "#666", marginBottom: 32 }}>
   134→        Your AI stylist, powered by Mira
   135→      </p>
   136→      <button
   137→        onClick={onStart}
   138→        style={{
   139→          background: "#111",
   140→          color: "#fff",
   141→          border: "none",
   142→          borderRadius: 12,
   143→          padding: "14px 40px",
   144→          fontSize: 16,
   145→          fontWeight: 600,
   146→          cursor: "pointer",
   147→        }}
   148→      >
   149→        Start Session
   150→      </button>
   151→      {error && (
   152→        <p style={{ color: "#c00", marginTop: 16, fontSize: 14 }}>{error}</p>
   153→      )}
   154→    </div>
   155→  );
   156→}
   157→
   158→function PhoneLoadingView() {
   159→  return (
   160→    <div
   161→      style={{
   162→        display: "flex",
   163→        flexDirection: "column",
   164→        alignItems: "center",
   165→        justifyContent: "center",
   166→        height: "100vh",
   167→        textAlign: "center",
   168→      }}
   169→    >
   170→      <p
   171→        style={{
   172→          fontSize: 20,
   173→          fontWeight: 500,
   174→          animation: "pulse 2s ease-in-out infinite",
   175→        }}
   176→      >
   177→        Mira is styling you...
   178→      </p>
   179→      <style>{`@keyframes pulse { 0%, 100% { opacity: 1; } 50% { opacity: 0.3; } }`}</style>
   180→    </div>
   181→  );
   182→}
   183→
   184→const STYLE_OPTIONS = [
   185→  "Casual",
   186→  "Streetwear",
   187→  "Minimalist",
   188→  "Preppy",
   189→  "Athleisure",
   190→  "Vintage",
   191→  "Smart Casual",
   192→  "Bohemian",
   193→];
   194→
   195→const OCCASION_OPTIONS = [
   196→  "Everyday",
