   203→
   204→function OnboardingView({ onSubmit }: { onSubmit: (d: OnboardingData) => void }) {
   205→  const [brands, setBrands] = useState("");
   206→  const [styles, setStyles] = useState<string[]>([]);
   207→  const [occasions, setOccasions] = useState<string[]>([]);
   208→  const [gender, setGender] = useState("unspecified");
   209→  const [priceMin, setPriceMin] = useState(0);
   210→  const [priceMax, setPriceMax] = useState(300);
   211→
   212→  function toggle(arr: string[], val: string, setter: (v: string[]) => void) {
   213→    setter(arr.includes(val) ? arr.filter((x) => x !== val) : [...arr, val]);
   214→  }
   215→
   216→  function handleSubmit() {
   217→    onSubmit({
   218→      favorite_brands: brands.split(",").map((b) => b.trim()).filter(Boolean),
   219→      style_preferences: styles,
   220→      price_range: { min: priceMin, max: priceMax },
   221→      size_info: {},
   222→      gender,
   223→      occasions,
   224→    });
   225→  }
   226→
   227→  const chipBase: React.CSSProperties = {
   228→    border: "1px solid #ccc",
   229→    borderRadius: 20,
   230→    padding: "8px 16px",
   231→    fontSize: 14,
   232→    cursor: "pointer",
