   247→      <p style={{ color: "#666", marginBottom: 24, fontSize: 14 }}>
   248→        Mira needs a bit of info to style you perfectly.
   249→      </p>
   250→
   251→      {/* Gender */}
   252→      <label style={{ fontWeight: 600, fontSize: 14 }}>Gender</label>
