    37→function MirrorPage() {
    38→  const searchParams = useSearchParams();
    39→  const userId = searchParams.get("user_id");
    40→
    41→  // Camera + gesture recognition
    42→  const { videoRef, isReady: isCameraReady, error: cameraError } = useCamera();
    43→  const [lastGesture, setLastGesture] = useState<GestureType | null>(null);
    44→  const gestureKeyRef = useRef(0);
    45→  const [gestureKey, setGestureKey] = useState(0);
    46→
    47→  // Session state
    48→  const [sessionActive, setSessionActive] = useState(false);
    49→  const [isStarting, setIsStarting] = useState(false);
    50→
    51→  // Pose detection + clothing overlay state
    52→  const [currentPose, setCurrentPose] = useState<PoseResult | null>(null);
    53→
    54→  interface CanvasOutfit {
    55→    name: string;
    56→    items: ClothingItem[];
    57→    productInfo: PriceStripItem[];
    58→  }
    59→  const [canvasOutfits, setCanvasOutfits] = useState<CanvasOutfit[]>([]);
    60→  const [canvasOutfitIndex, setCanvasOutfitIndex] = useState(0);
    61→  const activeCanvasOutfit = canvasOutfits[canvasOutfitIndex]?.items ?? [];
    62→  const activePriceItems = canvasOutfits[canvasOutfitIndex]?.productInfo ?? [];
    63→
    64→  // Orb avatar + voice
    65→  const orb = useOrbAvatar();
    66→  const stt = useDeepgramSTT();
    67→
    68→  // Queue transcripts while orb is speaking, send when quiet
    69→  const pendingTranscriptRef = useRef<string | null>(null);
    70→
    71→  // Accumulate full response text before delivering
    72→  const responseAccumulatorRef = useRef<string>("");
    73→
    74→  // Pose detection for clothing overlay
    75→  const handlePoseUpdate = useCallback((result: PoseResult) => {
    76→    setCurrentPose(result);
    77→  }, []);
    78→
    79→  usePoseDetection({
    80→    videoRef,
    81→    isVideoReady: isCameraReady,
