    84→
    85→  // Connect socket and join user room
    86→  useEffect(() => {
    87→    socket.connect();
    88→
    89→    if (userId) {
    90→      socket.emit("join_room", { user_id: userId });
    91→    }
    92→
    93→    return () => {
    94→      socket.disconnect();
    95→    };
    96→  }, [userId]);
    97→
    98→  // Listen for session_active from backend
    99→  useEffect(() => {
   100→    const handleSessionActive = () => {
   101→      setSessionActive(true);
   102→      setIsStarting(false);
   103→      setCanvasOutfits([]);
   104→      setCanvasOutfitIndex(0);
   105→      orb.startSession();
   106→      stt.startListening();
   107→    };
   108→
   109→    socket.on("session_active", handleSessionActive);
   110→    return () => {
   111→      socket.off("session_active", handleSessionActive);
   112→    };
   113→    // eslint-disable-next-line react-hooks/exhaustive-deps
   114→  }, []);
   115→
   116→  // Listen for mira_speech events (streamed text from AI)
   117→  useEffect(() => {
   118→    const handleSpeech = (data: { text?: string; is_chunk?: boolean }) => {
   119→      // Fallback session detection
   120→      if (!sessionActive && !isStarting) {
   121→        setSessionActive(true);
   122→        setIsStarting(false);
   123→        orb.startSession();
   124→        stt.startListening();
   125→      }
   126→
   127→      if (data.is_chunk !== false) {
   128→        // Still accumulating — skip empty chunks
   129→        if (!data.text) return;
   130→        console.log("[Mirror] mira_speech chunk received");
   131→        responseAccumulatorRef.current += data.text;
   132→        orb.setOrbState("thinking");
   133→      } else {
   134→        // End of message — accumulate any final text, then deliver
   135→        if (data.text) {
   136→          responseAccumulatorRef.current += data.text;
   137→        }
   138→        const fullText = responseAccumulatorRef.current;
   139→        responseAccumulatorRef.current = "";
   140→        console.log("[Mirror] Agent full response:", fullText);
   141→        if (!fullText) return;
   142→
   143→        // Parse emotion tag and stream TTS
   144→        const { emotion, cleanText } = parseEmotionTag(fullText);
   145→        console.log("[Mirror] Parsed emotion:", emotion);
   146→        orb.speak(cleanText, emotion);
   147→      }
   148→    };
   149→
   150→    socket.on("mira_speech", handleSpeech);
   151→    return () => {
   152→      socket.off("mira_speech", handleSpeech);
   153→    };
   154→    // eslint-disable-next-line react-hooks/exhaustive-deps
   155→  }, [sessionActive, isStarting]);
   156→
   157→  // Listen for tool_result events (product recommendations + voice messages)
   158→  useEffect(() => {
   159→    const handleToolResult = (data: {
   160→      type?: string;
   161→      tool?: string;
   162→      items?: { title: string; price?: string; [key: string]: unknown }[];
   163→      text?: string;
   164→      emotion?: string;
   165→      outfit_name?: string;
   166→    }) => {
   167→      // display_product: flat lay items from Gemini pipeline
   168→      if (data.type === "display_product" && data.items) {
   169→        const clothingItems = mapToClothingItems(data.items);
   170→        const priceInfo: PriceStripItem[] = data.items.map((it) => ({
   171→          title: it.title,
   172→          price: it.price,
   173→        }));
   174→        if (clothingItems.length > 0) {
   175→          setCanvasOutfits((prev) => {
