   383→              background: i === canvasOutfitIndex ? "#fff" : "rgba(255,255,255,0.3)",
   384→            }} />
   385→          ))}
   386→        </div>
   387→      )}
   388→
   389→      {/* Start Session button (pre-session overlay) */}
   390→      {!sessionActive && !isStarting && (
   391→        <div
   392→          style={{
   393→            position: "absolute",
   394→            top: "50%",
   395→            left: "50%",
